enum Level { info, debug, warning, error }

class LogRecord {
  final String _tag;
  final DateTime _timestamp;
  final int _levelIndex;
  final String _message;
  final String _error;

  LogRecord(this._tag, this._timestamp, this._levelIndex, this._message, this._error);

